def compute(inputs):
    cash_flows = inputs["cash_flows"]
    discount_rate = inputs["discount_rate"]
    initial_investment = inputs.get("initial_investment", 0.0)

    # Normalize discount rate if it's provided as a percentage (e.g., 8 for 8%) within a plausible range
    if discount_rate > 1 and discount_rate <= 100:
        discount_rate /= 100.0

    npv = -initial_investment
    for t, cash_flow in enumerate(cash_flows):
        npv += cash_flow / ((1 + discount_rate) ** (t + 1))

    return round(npv)

def compute(inputs):
    current_market_value = inputs["current_market_value"]
    original_investment_value = inputs["original_investment_value"]

    if original_investment_value <= 0:
        raise ValueError("Original investment value must be greater than zero.")

    rate_of_return = (current_market_value - original_investment_value) / original_investment_value
    nominal_rate_of_return = rate_of_return * 100

    return round(nominal_rate_of_return, 2)
